mapper.select:
SELECT * FROM ( SELECT u.USER_ID, u.EMAIL, u.FIRST_NAME, u.LAST_NAME, u.PHONE, u.STATUS, u.CREATED_AT, u.UPDATED_AT, NVL(order_stats.ORDER_COUNT, 0) as ORDER_COUNT, NVL(order_stats.TOTAL_SPENT, 0) as TOTAL_SPENT, NVL(order_stats.AVG_ORDER_VALUE, 0) as AVG_ORDER_VALUE, DECODE(u.STATUS, 'ACTIVE', 1, 'INACTIVE', 2, 'SUSPENDED', 3, 4) as STATUS_PRIORITY, DENSE_RANK() OVER (ORDER BY NVL(order_stats.TOTAL_SPENT, 0) DESC) as SPENDING_RANK,
CASE WHEN NVL(order_stats.TOTAL_SPENT, 0) >= 10000 THEN 'VIP' WHEN NVL(order_stats.TOTAL_SPENT, 0) >= 1000 THEN 'PREMIUM' WHEN NVL(order_stats.ORDER_COUNT, 0) > 0 THEN 'REGULAR' ELSE 'NEW' END as USER_GRADE,
TRUNC(SYSDATE) - TRUNC(u.CREATED_AT) as DAYS_SINCE_REGISTRATION, ROW_NUMBER() OVER (ORDER BY u.CREATED_AT DESC) as RN FROM USERS u, (SELECT o.USER_ID, COUNT(*) as ORDER_COUNT, SUM(o.TOTAL_AMOUNT) as TOTAL_SPENT, ROUND(AVG(o.TOTAL_AMOUNT), 2) as AVG_ORDER_VALUE, MAX(o.ORDERED_AT) as LAST_ORDER_DATE FROM ORDERS o WHERE o.ORDER_STATUS NOT IN ('CANCELLED', 'REFUNDED') GROUP BY o.USER_ID) order_stats WHERE u.USER_ID = order_stats.USER_ID(+)
AND UPPER(u.EMAIL) LIKE '%' || UPPER(#{email}) || '%'
AND u.STATUS = #{status}
AND CASE WHEN NVL(order_stats.TOTAL_SPENT, 0) >= 10000 THEN 'VIP' WHEN NVL(order_stats.TOTAL_SPENT, 0) >= 1000 THEN 'PREMIUM' WHEN NVL(order_stats.ORDER_COUNT, 0) > 0 THEN 'REGULAR' ELSE 'NEW' END = #{userGrade}
AND u.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND u.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND NVL(order_stats.TOTAL_SPENT, 0) >= #{minSpent}
AND NVL(order_stats.TOTAL_SPENT, 0) <= #{maxSpent}
)
WHERE ROWNUM <= #{offset} + #{limit} AND RN > #{offset}
ORDER BY STATUS_PRIORITY, SPENDING_RANK

SELECT COUNT(*) as count FROM USERS u, (SELECT o.USER_ID, COUNT(*) as ORDER_COUNT, SUM(o.TOTAL_AMOUNT) as TOTAL_SPENT FROM ORDERS o WHERE o.ORDER_STATUS NOT IN ('CANCELLED', 'REFUNDED') GROUP BY o.USER_ID) order_stats WHERE u.USER_ID = order_stats.USER_ID(+)
AND UPPER(u.EMAIL) LIKE '%' || UPPER(#{email}) || '%'
AND u.STATUS = #{status}
AND CASE WHEN NVL(order_stats.TOTAL_SPENT, 0) >= 10000 THEN 'VIP' WHEN NVL(order_stats.TOTAL_SPENT, 0) >= 1000 THEN 'PREMIUM' WHEN NVL(order_stats.ORDER_COUNT, 0) > 0 THEN 'REGULAR' ELSE 'NEW' END = #{userGrade}
AND u.CREATED_AT >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND u.CREATED_AT <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND NVL(order_stats.TOTAL_SPENT, 0) >= #{minSpent}
AND NVL(order_stats.TOTAL_SPENT, 0) <= #{maxSpent}
